//! xtask: project automation runner.
//!
//! Subcommands:
//!   build          — cross-compile the kernel
//!   qemu           — build then boot in QEMU virt
//!   qemu --gdb     — same, but pause for a gdb connection on :1234

use std::env;
use std::path::{Path, PathBuf};
use std::process::{Command, ExitCode, Stdio};

const KERNEL_TARGET: &str = "riscv64gc-unknown-none-elf";
const KERNEL_PKG: &str = "kernel";

fn main() -> ExitCode {
    let args: Vec<String> = env::args().collect();
    let cmd = args.get(1).map(String::as_str).unwrap_or("help");
    let rest = &args[2.min(args.len())..];

    let res = match cmd {
        "build" => cmd_build(rest),
        "qemu" => cmd_qemu(rest),
        "help" | "--help" | "-h" => {
            print_help();
            Ok(())
        }
        other => {
            eprintln!("xtask: unknown subcommand `{other}`");
            print_help();
            return ExitCode::from(2);
        }
    };

    match res {
        Ok(()) => ExitCode::SUCCESS,
        Err(e) => {
            eprintln!("xtask: {e}");
            ExitCode::FAILURE
        }
    }
}

fn print_help() {
    eprintln!(
        "xtask — xiande-os automation\n\
         \n\
         USAGE:\n    cargo xtask <subcommand> [flags]\n\
         \n\
         SUBCOMMANDS:\n\
             build         Cross-compile the kernel\n\
             qemu          Build kernel and run under QEMU virt\n\
         \n\
         QEMU FLAGS:\n\
             --release     Build in release mode (default)\n\
             --debug       Build in dev mode\n\
             --gdb         Pause QEMU at startup and wait for gdb on :1234\n\
             --smp <N>     Use N harts (default 1 for M0)\n"
    );
}

#[derive(Clone, Copy)]
enum Profile {
    Release,
    Dev,
}

impl Profile {
    fn dir(self) -> &'static str {
        match self {
            Profile::Release => "release",
            Profile::Dev => "debug",
        }
    }
    fn cargo_flag(self) -> Option<&'static str> {
        match self {
            Profile::Release => Some("--release"),
            Profile::Dev => None,
        }
    }
}

fn cmd_build(args: &[String]) -> Result<(), String> {
    let profile = parse_profile(args);
    build_kernel(profile)?;
    let elf = kernel_elf_path(profile);
    println!("kernel ELF: {}", elf.display());
    Ok(())
}

fn parse_profile(args: &[String]) -> Profile {
    if args.iter().any(|a| a == "--debug") {
        Profile::Dev
    } else {
        Profile::Release
    }
}

fn build_kernel(profile: Profile) -> Result<(), String> {
    let workspace = workspace_root();
    let kernel_dir = workspace.join("kernel");
    let mut cmd = Command::new(cargo());
    cmd.current_dir(&kernel_dir)
        .arg("build")
        .arg("--target")
        .arg(KERNEL_TARGET);
    if let Some(flag) = profile.cargo_flag() {
        cmd.arg(flag);
    }
    if let Ok(features) = env::var("KERNEL_FEATURES") {
        if !features.is_empty() {
            cmd.arg("--features").arg(features);
        }
    }
    let status = cmd
        .stdout(Stdio::inherit())
        .stderr(Stdio::inherit())
        .status()
        .map_err(|e| format!("cargo build failed to spawn: {e}"))?;
    if !status.success() {
        return Err(format!("cargo build exited with status {status}"));
    }
    Ok(())
}

fn cmd_qemu(args: &[String]) -> Result<(), String> {
    let profile = parse_profile(args);
    let gdb = args.iter().any(|a| a == "--gdb");
    let smp = parse_smp(args)?;
    build_kernel(profile)?;
    let elf = kernel_elf_path(profile);
    if !elf.exists() {
        return Err(format!("kernel ELF not found at {}", elf.display()));
    }

    let workspace = workspace_root();
    let disk = workspace.join("user/disk.img");
    let mut qemu = Command::new("qemu-system-riscv64");
    qemu.args([
        "-machine",
        "virt",
        "-nographic",
        "-bios",
        "default",
        "-kernel",
    ])
    .arg(&elf)
    .args(["-smp", &smp.to_string()])
    .args(["-m", "1G"]);
    if disk.exists() {
        qemu.args(["-drive"])
            .arg(format!("file={},format=raw,id=vd0,if=none", disk.display()))
            .args(["-device", "virtio-blk-device,drive=vd0"]);
    }

    // QEMU user-mode networking: host=10.0.2.2, DNS=10.0.2.3, guest=10.0.2.15.
    // Forward host TCP 15555 to guest 5555 so a guest server on :5555 can
    // accept inbound from the host via 127.0.0.1:15555. Outbound from the
    // kernel to host services on 10.0.2.2:5555 works without any extra
    // hostfwd thanks to SLIRP.
    qemu.args(["-netdev", "user,id=net0,hostfwd=tcp::15555-:5555"])
        .args(["-device", "virtio-net-device,netdev=net0"]);

    if gdb {
        qemu.args(["-s", "-S"]);
        eprintln!("qemu: paused for gdb on :1234 (use `target remote :1234`)");
    }

    eprintln!("qemu: launching {}", elf.display());
    let status = qemu
        .stdout(Stdio::inherit())
        .stderr(Stdio::inherit())
        .stdin(Stdio::inherit())
        .status()
        .map_err(|e| format!("qemu failed to spawn: {e}"))?;

    if !status.success() {
        // QEMU exits non-zero when the guest issues system_reset; that's normal.
        // Treat any non-signal exit as success here (the guest output already shown).
        eprintln!("qemu exited with {status}");
    }
    Ok(())
}

fn parse_smp(args: &[String]) -> Result<u32, String> {
    let mut it = args.iter();
    while let Some(a) = it.next() {
        if a == "--smp" {
            let v = it
                .next()
                .ok_or_else(|| "--smp requires a value".to_string())?;
            return v
                .parse::<u32>()
                .map_err(|e| format!("invalid --smp value `{v}`: {e}"));
        }
    }
    Ok(1)
}

fn workspace_root() -> PathBuf {
    // CARGO_MANIFEST_DIR points at xtask/. Workspace root is the parent.
    let here = Path::new(env!("CARGO_MANIFEST_DIR"));
    here.parent()
        .map(Path::to_path_buf)
        .unwrap_or_else(|| here.to_path_buf())
}

fn cargo() -> String {
    env::var("CARGO").unwrap_or_else(|_| "cargo".to_string())
}

fn kernel_elf_path(profile: Profile) -> PathBuf {
    workspace_root()
        .join("target")
        .join(KERNEL_TARGET)
        .join(profile.dir())
        .join(KERNEL_PKG)
}

use std::env;
use std::path::PathBuf;

fn copy_or_stub(src: PathBuf, dst: PathBuf, env_var: &str) {
    if src.exists() {
        std::fs::copy(&src, &dst).unwrap_or_else(|e| {
            panic!("copy {} -> {}: {e}", src.display(), dst.display())
        });
        println!("cargo:rerun-if-changed={}", src.display());
    } else {
        // No prebuilt available (e.g. contest mode, evaluator stripped binaries).
        // Emit an empty placeholder so include_bytes! still compiles.
        std::fs::write(&dst, []).unwrap();
    }
    println!("cargo:rustc-env={}={}", env_var, dst.display());
}

fn main() {
    let manifest_dir = PathBuf::from(env::var("CARGO_MANIFEST_DIR").unwrap());
    let workspace_root = manifest_dir.parent().unwrap().to_path_buf();
    let user_dir = workspace_root.join("user");
    let out_dir = PathBuf::from(env::var("OUT_DIR").unwrap());

    // Linker script for the kernel itself (absolute path so rust-lld can
    // find it regardless of cwd at link time). Pick the per-architecture
    // script based on the target cargo is building for.
    let target_arch = env::var("CARGO_CFG_TARGET_ARCH").unwrap_or_default();
    let linker_name = if target_arch == "loongarch64" {
        "linker-la.ld"
    } else {
        "linker.ld"
    };
    let linker_script = manifest_dir.join(linker_name);
    println!("cargo:rustc-link-arg=-T{}", linker_script.display());
    println!("cargo:rerun-if-changed=linker.ld");
    println!("cargo:rerun-if-changed=linker-la.ld");

    // For each embedded user-mode binary, prefer a checked-in prebuilt.
    // The contest harness rejects on-line dependency downloads, so we
    // never spawn nested `cargo build` invocations for the user-land
    // workspace from here — that wiring is now in xtask.
    //
    // The prebuilt user binaries are RISC-V ELFs; for a loongarch64 kernel
    // the embedded `hello` is the freestanding LA test program (built from
    // user/hello-la.S) so the LA port can exercise user mode without a disk.
    let hello_src = if target_arch == "loongarch64" {
        "hello-la.elf"
    } else {
        "hello.elf"
    };
    copy_or_stub(
        user_dir.join(hello_src),
        out_dir.join("hello.elf"),
        "HELLO_ELF_PATH",
    );
    copy_or_stub(
        user_dir.join("musl_hello.elf"),
        out_dir.join("musl_hello.elf"),
        "MUSL_HELLO_ELF_PATH",
    );
    copy_or_stub(
        user_dir.join("git.elf"),
        out_dir.join("git.elf"),
        "GIT_ELF_PATH",
    );
    copy_or_stub(
        user_dir.join("real_git.elf"),
        out_dir.join("real_git.elf"),
        "REAL_GIT_ELF_PATH",
    );
    copy_or_stub(
        user_dir.join("busybox.elf"),
        out_dir.join("busybox.elf"),
        "BUSYBOX_ELF_PATH",
    );
    copy_or_stub(
        user_dir.join("dyn_hello.elf"),
        out_dir.join("dyn_hello.elf"),
        "DYN_HELLO_ELF_PATH",
    );
    copy_or_stub(
        user_dir.join("ld-musl-riscv64.so.1"),
        out_dir.join("ld-musl-riscv64.so.1"),
        "LD_MUSL_PATH",
    );
    // Freestanding LoongArch "hello" used by the `la_hello` boot feature to
    // smoke-test user paging + the first syscall end-to-end on LA. Empty
    // placeholder on RV (or if the prebuilt is absent).
    copy_or_stub(
        user_dir.join("la_hello.elf"),
        out_dir.join("la_hello.elf"),
        "LA_HELLO_ELF_PATH",
    );

    // In-kernel symbol table ("ksyms"). `ksyms.rs` does
    // `include_bytes!(env!("KSYMS_BIN_PATH"))`; we point it straight at
    // `ksyms-<arch>.bin` at the workspace root. A post-link Makefile step
    // (`ksyms-embed`) regenerates that file from the just-linked kernel and
    // rebuilds — rustc tracks include_bytes! inputs in its dep-info, so the
    // second `cargo build` recompiles `ksyms.rs` with the real table and
    // relinks (two-pass). The blob lives in .rodata (after .text in the link),
    // so embedding it never moves a .text address, and the addresses a pass-1
    // blob records stay correct for the pass-2 kernel.
    //
    // A normal one-pass build (or a direct `cargo build`) just sees the empty
    // placeholder created here — `ksyms::resolve` returns None and the kernel
    // prints raw addresses exactly as before. So this is purely additive and
    // can never break the build.
    let ksyms = workspace_root.join(format!("ksyms-{target_arch}.bin"));
    if !ksyms.exists() {
        let _ = std::fs::write(&ksyms, []);
    }
    // Re-run this script (and recompile ksyms.rs) whenever the blob is
    // (re)generated or removed — this recreates the placeholder on a rebuild
    // where the file was deleted but the cached build script would otherwise be
    // skipped, and drives the pass-2 pickup of a freshly generated table.
    println!("cargo:rerun-if-changed={}", ksyms.display());
    println!("cargo:rustc-env=KSYMS_BIN_PATH={}", ksyms.display());
}

//! Arch dispatcher.
//!
//! Architecture differences are confined to `arch/<arch>/`. The rest of
//! the kernel calls the architecture-neutral functions re-exported here
//! (`now_ticks`, `shutdown`, `console_put`, ...) and never references a
//! specific ISA. Each backend module supplies the same set of names; the
//! `#[cfg(target_arch)]` gate selects which one is linked.
//!
//! This mirrors Linux's `arch/` model: a naming contract that every
//! architecture must satisfy, with no `#[cfg]` leaking into the common
//! layers above.

#[cfg(target_arch = "riscv64")]
pub mod riscv64;

#[cfg(target_arch = "riscv64")]
use riscv64 as imp;

#[cfg(target_arch = "loongarch64")]
pub mod loongarch64;

#[cfg(target_arch = "loongarch64")]
use loongarch64 as imp;

/// The architecture's trap frame. Common code (`signal`, `syscall`,
/// `task`) names it through this re-export and only ever touches it via
/// its inherent methods, so it is portable across backends.
pub use imp::trap::TrapFrame;

/// Per-task parked kernel context (callee-saved regs + sp), backend-defined.
/// The scheduler switches between tasks by saving one and restoring another.
pub use imp::context::TaskContext;

/// Switch kernel execution from the task whose context is `prev` to the one
/// whose context is `next`: saves the current callee-saved state into `prev`
/// and resumes `next` where it last switched out. Returns (in the original
/// task's timeline) once that task is scheduled again.
///
/// # Safety
/// `prev` and `next` must point to valid `TaskContext`s for live tasks with
/// intact kernel stacks, and no kernel lock may be held across the call.
#[inline]
pub unsafe fn switch_context(prev: *mut TaskContext, next: *const TaskContext) {
    imp::context::__switch(prev, next)
}

// ---- Traps ------------------------------------------------------------

/// Install the trap vector(s) and start the preemption timer. Call once
/// during early boot, after the console is up.
pub fn trap_init() {
    imp::trap::init();
}

// ---- MMU --------------------------------------------------------------

/// Make the address space identified by `token` (the value returned by
/// `mm::PageTable::satp()`) the active translation and flush stale TLB
/// entries.
#[inline]
pub fn activate_page_table(token: usize) {
    imp::mm::activate(token);
}

/// Invalidate the local-hart TLB entry covering virtual address `va`.
#[inline]
pub fn flush_tlb_va(va: usize) {
    imp::mm::flush_va(va);
}

/// Flush the entire local-hart TLB.
#[inline]
pub fn flush_tlb_all() {
    imp::mm::flush_all();
}

// ---- Time -------------------------------------------------------------

/// Raw monotonic tick counter. Unit is architecture-defined; convert via
/// [`TICKS_PER_SEC`]. On riscv64 QEMU virt this is the 10 MHz mtime CSR.
#[inline]
pub fn now_ticks() -> u64 {
    imp::time::now_ticks()
}

/// Ticks of [`now_ticks`] per wall-clock second.
pub const TICKS_PER_SEC: u64 = imp::time::TICKS_PER_SEC;

/// Tell the timer layer the raw counter frequency the platform advertises (the
/// device tree's `timebase-frequency`). riscv64 rescales its mtime to the fixed
/// `TICKS_PER_SEC` from this; loongarch64 reads a constant-rate counter and
/// ignores it. Call once, early in boot.
#[inline]
pub fn set_timer_raw_hz(hz: u64) {
    #[cfg(target_arch = "riscv64")]
    imp::time::set_raw_hz(hz);
