    fn write_str(&mut self, s: &str) -> fmt::Result {
        for &b in s.as_bytes() {
            crate::arch::console_put(b);
        }
        Ok(())
    }
}

pub fn _print(args: fmt::Arguments<'_>) {
    let _ = Console.write_fmt(args);
}

